SELECT CHAMADA.AREA_INGRESSO FROM (SELECT C.AREA_INGRESSO, COUNT(DISTINCT C.SIAPE) AS QTD_SERVIDORES FROM CALC_HORA_AULA_MEDIA C WHERE C.ANO = 2020 AND C.SEMESTRE = 1 AND LOWER(C.SIGLA_CAMPUS) = LOWER('ana') AND C.SIAPE IN (SELECT S.PK_SIAPE FROM SERVIDOR S WHERE LOWER(S.CONTRATO) = LOWER('efetivos')) GROUP BY C.AREA_INGRESSO HAVING COUNT(DISTINCT C.SIAPE) = 5) AS CHAMADA LIMIT 1